 1	import React, { FC, useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { IoK8sApiBatchV1Job, IoK8sApiCoreV1ConfigMap } from '@kubevirt-ui/kubevirt-api/kubernetes';
 5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 6	import DropdownToggle from '@kubevirt-utils/components/toggles/DropdownToggle';
 7	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
10	import { Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
11	
12	import DeleteCheckupModal from '../../components/DeleteCheckupModal';
13	import { STATUS_SUCCEEDED } from '../../utils/utils';
14	import { deleteNetworkCheckup, rerunNetworkCheckup } from '../utils/utils';
15	
16	type CheckupsNetworkActionsProps = {
17	  configMap: IoK8sApiCoreV1ConfigMap;
18	  isKebab?: boolean;
19	  jobs: IoK8sApiBatchV1Job[];
20	};
21	
22	const CheckupsNetworkActions: FC<CheckupsNetworkActionsProps> = ({
23	  configMap,
24	  isKebab = false,
25	  jobs,
26	}) => {
27	  const { t } = useKubevirtTranslation();
28	  const navigate = useNavigate();
29	  const { createModal } = useModal();
30	  const [isActionsOpen, setIsActionsOpen] = useState<boolean>(false);
31	
32	  const onToggle = () => setIsActionsOpen((prevIsOpen) => !prevIsOpen);
33	  const Toggle = isKebab
34	    ? KebabToggle({ isExpanded: isActionsOpen, onClick: onToggle })
35	    : DropdownToggle({ isExpanded: isActionsOpen, onClick: onToggle, placeholder: t('Actions') });
36	
37	  const deleteCheckup = () => {
38	    setIsActionsOpen(false);
39	    deleteNetworkCheckup(configMap, jobs);
40	    navigate(`/k8s/ns/${configMap?.metadata?.namespace}/checkups`);
41	  };
42	
43	  return (
44	    <Dropdown
45	      isOpen={isActionsOpen}
46	      onOpenChange={(open: boolean) => setIsActionsOpen(open)}
47	      toggle={Toggle}
48	    >
49	      <DropdownList>
50	        <DropdownItem
51	          onClick={() =>
52	            createModal((props) => (
53	              <DeleteCheckupModal
54	                {...props}
55	                name={getName(configMap)}
56	                namespace={getNamespace(configMap)}
57	                onDelete={deleteCheckup}
58	              />
59	            ))
60	          }
61	          key="delete"
62	        >
63	          {t('Delete')}
64	        </DropdownItem>
65	        <DropdownItem
66	          onClick={() => {
67	            setIsActionsOpen(false);
68	            return rerunNetworkCheckup(configMap);
69	          }}
70	          isDisabled={configMap?.data?.[STATUS_SUCCEEDED] === undefined}
71	          key="rerun"
72	        >
73	          {t('Rerun')}
74	        </DropdownItem>
75	      </DropdownList>
76	    </Dropdown>
77	  );
78	};
79	
80	export default CheckupsNetworkActions;

